# Configuration
LOG_FILE = os.path.join(os.path.dirname(os.path.abspath(__file__)), "application.log")
LOG_MAX_SIZE = 10 * 1024 * 1024  # 10 MB
ALLOWED_LOG_LEVELS = {"DEBUG", "INFO", "WARNING", "ERROR", "CRITICAL"}
MAX_MESSAGE_LENGTH = 4096
MAX_SERVICE_NAME_LENGTH = 128
LISTEN_HOST = "127.0.0.1"
LISTEN_PORT = 8080

# Lock for thread-safe file writing
_log_lock = threading.Lock()


def sanitize_log_message(message):
    """
    Sanitize a log message to prevent log injection attacks.
    
    - Removes or escapes newline characters, carriage returns, and other
      control characters that could be used for log injection/forging.
    - Truncates to maximum allowed length.
    - Escapes HTML entities to prevent log viewer XSS if logs are viewed in browser.
    """
    if not isinstance(message, str):
        message = str(message)

    # Remove null bytes
    message = message.replace('\x00', '')

    # Replace newlines and carriage returns with escaped versions
    # This prevents log injection where an attacker injects fake log entries
    message = message.replace('\r\n', '\\r\\n')
    message = message.replace('\r', '\\r')
    message = message.replace('\n', '\\n')

    # Remove other ASCII control characters (0x01-0x1F except tab, and 0x7F)
    message = re.sub(r'[\x01-\x08\x0b\x0c\x0e-\x1f\x7f]', '', message)

    # Replace tab with spaces for consistent formatting
    message = message.replace('\t', '    ')

    # Truncate to max length
    if len(message) > MAX_MESSAGE_LENGTH:
        message = message[:MAX_MESSAGE_LENGTH] + "...[TRUNCATED]"

    return message


def sanitize_service_name(service_name):
    """
    Sanitize service name to only allow alphanumeric characters, hyphens,
    underscores, and dots.
    """
    if not isinstance(service_name, str):
        service_name = str(service_name)

    # Only allow safe characters in service names
    sanitized = re.sub(r'[^a-zA-Z0-9._\-]', '_', service_name)

    # Truncate
    if len(sanitized) > MAX_SERVICE_NAME_LENGTH:
        sanitized = sanitized[:MAX_SERVICE_NAME_LENGTH]

    return sanitized


def sanitize_log_level(level):
    """Validate and sanitize log level."""
    if not isinstance(level, str):
        level = str(level)

    level = level.upper().strip()

    if level not in ALLOWED_LOG_LEVELS:
        return "INFO"

    return level


def sanitize_ip_address(ip):
    """Sanitize IP address string."""
    if not isinstance(ip, str):
        ip = str(ip)

    # Basic IP validation - allow IPv4 and IPv6 characters only
    sanitized = re.sub(r'[^a-fA-F0-9.:[\]]', '', ip)

    if len(sanitized) > 45:  # Max IPv6 length
        sanitized = sanitized[:45]

    return sanitized


def rotate_log_if_needed():
    """Rotate log file if it exceeds maximum size."""
    try:
        if os.path.exists(LOG_FILE) and os.path.getsize(LOG_FILE) > LOG_MAX_SIZE:
            rotated_name = LOG_FILE + ".1"
            if os.path.exists(rotated_name):
                os.remove(rotated_name)
            os.rename(LOG_FILE, rotated_name)
    except OSError:
        pass  # If rotation fails, continue logging to current file


def write_log_entry(timestamp, level, service, source_ip, request_id, message):
    """
    Write a single log entry to the log file in a safe, atomic manner.
    Uses string formatting with pre-sanitized values only.
    """
    # All inputs must be sanitized before calling this function
    log_line = "[{timestamp}] [{level}] [{service}] [src:{source_ip}] [req:{request_id}] {message}\n".format(
        timestamp=timestamp,
        level=level,
        service=service,
        source_ip=source_ip,
        request_id=request_id,
        message=message
    )

    with _log_lock:
        rotate_log_if_needed()
        # Use 'a' mode for append; write is atomic for lines < PIPE_BUF on POSIX
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            f.write(log_line)
            f.flush()
            os.fsync(f.fileno())


def sanitize_request_id(request_id):
    """Sanitize request/correlation ID."""
    if not isinstance(request_id, str):
        request_id = str(request_id)

    # Only allow safe characters: alphanumeric, hyphens, underscores
    sanitized = re.sub(r'[^a-zA-Z0-9_\-]', '', request_id)

    if len(sanitized) > 64:
        sanitized = sanitized[:64]

    if not sanitized:
        sanitized = "none"

    return sanitized


def process_log_request(log_data, source_ip):
    """
    Process a log request with full sanitization.
    
    Expected log_data dict keys:
        - message (str): The log message
        - level (str): Log level (DEBUG, INFO, WARNING, ERROR, CRITICAL)
        - service (str): Name of the originating microservice
        - request_id (str, optional): Correlation/request ID for tracing
    """
    # Extract and sanitize all fields
    raw_message = log_data.get("message", "")
    raw_level = log_data.get("level", "INFO")
    raw_service = log_data.get("service", "unknown")
    raw_request_id = log_data.get("request_id", "none")

    sanitized_message = sanitize_log_message(raw_message)
    sanitized_level = sanitize_log_level(raw_level)
    sanitized_service = sanitize_service_name(raw_service)
    sanitized_ip = sanitize_ip_address(source_ip)
    sanitized_request_id = sanitize_request_id(raw_request_id)

    # Generate timestamp server-side (don't trust client timestamps for the log record)
    timestamp = datetime.datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%S.%fZ")

    # Validate that we have a non-empty message after sanitization
    if not sanitized_message.strip():
        return False, "Empty message after sanitization"

    write_log_entry(
        timestamp=timestamp,
        level=sanitized_level,
        service=sanitized_service,
        source_ip=sanitized_ip,
        request_id=sanitized_request_id,
        message=sanitized_message
    )

    return True, "Log entry recorded"


def process_batch_log_request(batch_data, source_ip):
    """Process a batch of log entries."""
    entries = batch_data.get("entries", [])

    if not isinstance(entries, list):
        return False, "entries must be a list"

    if len(entries) > 100:
        return False, "Maximum 100 entries per batch"

    results = []
    for i, entry in enumerate(entries):
        if not isinstance(entry, dict):
            results.append({"index": i, "success": False, "error": "Invalid entry format"})
            continue

        success, msg = process_log_request(entry, source_ip)
        results.append({"index": i, "success": success, "message": msg})

    all_success = all(r["success"] for r in results)
    return all_success, results


class LogRequestHandler(BaseHTTPRequestHandler):
    """HTTP request handler for the centralized logging service."""

    # Suppress default logging to stderr to avoid log injection via access logs
    def log_message(self, format, *args):
        """Override to sanitize access log output."""
        sanitized_args = []
        for arg in args:
            sanitized_args.append(sanitize_log_message(str(arg)))
        # Write access log through our safe logging mechanism
        process_log_request(
            {
                "message": "ACCESS: " + " ".join(sanitized_args),
                "level": "DEBUG",
                "service": "log-server",
                "request_id": "internal"
            },
            self.client_address[0]
        )

    def _send_json_response(self, status_code, data):
        """Send a JSON response."""
        response_body = json.dumps(data).encode('utf-8')
        self.send_response(status_code)
        self.send_header('Content-Type', 'application/json')
        self.send_header('Content-Length', str(len(response_body)))
        # Security headers
        self.send_header('X-Content-Type-Options', 'nosniff')
        self.send_header('Cache-Control', 'no-store')
        self.end_headers()
        self.wfile.write(response_body)

    def _read_request_body(self, max_size=65536):
        """Read and parse JSON request body with size limit."""
        content_length = self.headers.get('Content-Length')

        if content_length is None:
            return None, "Missing Content-Length header"

        try:
            content_length = int(content_length)
        except (ValueError, TypeError):
            return None, "Invalid Content-Length"

        if content_length > max_size:
            return None, "Request body too large (max {} bytes)".format(max_size)

        if content_length < 0:
            return None, "Invalid Content-Length"

        raw_body = self.rfile.read(content_length)

        try:
            data = json.loads(raw_body.decode('utf-8'))
        except (json.JSONDecodeError, UnicodeDecodeError) as e:
            return None, "Invalid JSON: {}".format(sanitize_log_message(str(e)))

        if not isinstance(data, dict):
            return None, "Request body must be a JSON object"

        return data, None

    def do_POST(self):
        """Handle POST requests for log submission."""
        parsed_path = urlparse(self.path)
        path = parsed_path.path

        # Verify content type
        content_type = self.headers.get('Content-Type', '')
        if 'application/json' not in content_type:
            self._send_json_response(415, {
                "success": False,
                "error": "Content-Type must be application/json"
            })
            return

        source_ip = self.client_address[0]

        if path == '/log':
            # Single log entry
            data, error = self._read_request_body()
            if error:
                self._send_json_response(400, {"success": False, "error": error})
                return

            success, message = process_log_request(data, source_ip)

            if success:
                self._send_json_response(200, {"success": True, "message": message})
            else:
                self._send_json_response(400, {"success": False, "error": message})

        elif path == '/log/batch':
            # Batch log entries
            data, error = self._read_request_body(max_size=1048576)  # 1MB for batch
            if error:
                self._send_json_response(400, {"success": False, "error": error})
                return

            success, results = process_batch_log_request(data, source_ip)

            status_code = 200 if success else 207  # 207 Multi-Status for partial success
            self._send_json_response(status_code, {
                "success": success,
                "results": results
            })

        else:
            self._send_json_response(404, {"success": False, "error": "Not found"})

    def do_GET(self):
        """Handle GET requests - health check only."""
        parsed_path = urlparse(self.path)

        if parsed_path.path == '/health':
            self._send_json_response(200, {
                "status": "healthy",
                "service": "centralized-log-server"
            })
        else:
            self._send_json_response(404, {"success": False, "error": "Not found"})


def run_server(host=LISTEN_HOST, port=LISTEN_PORT):
    """Start the centralized logging HTTP server."""
    server = HTTPServer((host, port), LogRequestHandler)

    # Log server startup
    process_log_request(
        {
            "message": "Centralized logging server started on {}:{}".format(host, port),
            "level": "INFO",
            "service": "log-server",
            "request_id": "startup"
        },
        "127.0.0.1"
    )

    print("Centralized Logging Server running on http://{}:{}".format(host, port))
    print("Log file: {}".format(LOG_FILE))
    print("Endpoints:")
    print("  POST /log       - Submit a single log entry")
    print("  POST /log/batch - Submit multiple log entries")
    print("  GET  /health    - Health check")

    try:
        server.serve_forever()
    except KeyboardInterrupt:
        process_log_request(
            {
                "message": "Centralized logging server shutting down",
                "level": "INFO",
                "service": "log-server",
                "request_id": "shutdown"
            },
            "127.0.0.1"
        )
        server.shutdown()
        print("\nServer stopped.")


