def send_log(message, level="INFO", service="unknown", request_id=None,
             host=LISTEN_HOST, port=LISTEN_PORT):
    """
    Convenience function to send a log entry to the centralized logging server.
    Can be used by microservices as a simple client.
    """
    import urllib.request

    log_data = {
        "message": message,
        "level": level,
        "service": service,
    }
    if request_id:
        log_data["request_id"] = request_id

    payload = json.dumps(log_data).encode('utf-8')

    req = urllib.request.Request(
        "http://{}:{}/log".format(host, port),
        data=payload,
        headers={"Content-Type": "application/json"},
        method="POST"
    )

    try:
        with urllib.request.urlopen(req, timeout=5) as response:
            return json.loads(response.read().decode('utf-8'))
    except Exception as e:
        return {"success": False, "error": str(e)}


